'use client';

import { useCallback, useMemo, useRef, useState } from 'react';
import {
  Background,
  BackgroundVariant,
  type Edge,
  Controls,
  MiniMap,
  ReactFlow,
} from 'reactflow';

import { useCanvasBoard } from '../../hooks/useCanvasBoard';
import { FloatingToolbar } from './FloatingToolbar';
import { TopNavigation } from './TopNavigation';
