    return 'Saved';
  }

  if (status === 'error') {
    return 'Sync error';
  }

  return 'Ready';
}

export function TopNavigation({
  persistenceStatus,
  persistenceError,
  currentStep,
  onStepClick,
}: TopNavigationProps) {
  const steps = [
    { id: 1, label: 'BRAINSTORMING' },
    { id: 2, label: 'CHOICE' },
    { id: 3, label: 'GENERATING' },
  ];

  return (
    <header className="pointer-events-none fixed inset-x-0 top-0 z-20 flex justify-center px-4 pt-4">
