                  {selectedTemplate.animationPrompt}
                </p>
              </div>
              <div className="mt-3 grid gap-2 rounded-2xl border border-dashed border-slate-200 bg-white px-4 py-3 text-sm text-slate-600 sm:grid-cols-2">
                <div className="flex items-center gap-2">
                  <ImageIcon className="size-4 text-slate-400" />
                  <span>{TEMPLATE_ASSET_DIRECTORIES.images}</span>
                </div>
                <div className="flex items-center gap-2">
                  <Film className="size-4 text-slate-400" />
                  <span>{TEMPLATE_ASSET_DIRECTORIES.videos}</span>
                </div>
              </div>
            </div>
          ) : null}
          <div className="flex gap-2">
            <button
              type="button"
              onClick={handleTemplateSubmit}
              className="rounded-full bg-slate-900 px-4 py-3 text-sm font-medium text-white transition hover:bg-slate-800 disabled:cursor-not-allowed disabled:opacity-50"
              disabled={isApplyingTemplate || !selectedTemplateId}
            >
              {isApplyingTemplate ? 'Applying...' : 'Add template'}
            </button>
            <button
              type="button"
              onClick={closePanel}
              className="rounded-full border border-slate-200 bg-white px-4 py-3 text-sm font-medium text-slate-600 transition hover:text-slate-900"
            >
              Cancel
            </button>
          </div>
        </div>
      </WorkspaceActionPanel>
    ) : null}

