            className="flex items-center justify-center gap-2 rounded-full bg-slate-900 py-3 text-sm font-medium text-white transition hover:bg-slate-800 disabled:opacity-50"
          >
            <Sparkles className="size-4" />
            {isGenerating ? 'Generating...' : 'Start Generation'}
          </button>
        </div>
      </WorkspaceActionPanel>
    ) : null}

    {activePanel === 'scrape' ? (
      <WorkspaceActionPanel
        title="Search & Scrape Research"
        description="Search the web with Tavily and summarize insights using Gemini to build your content strategy."
        onClose={closePanel}
      >
        <div className="flex flex-col gap-4">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 size-4 -translate-y-1/2 text-slate-400" />
            <input
              type="text"
              placeholder="What are the current trends in..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full rounded-full border border-slate-200 bg-white py-3 pl-10 pr-4 text-sm outline-none transition focus:border-slate-400"
            />
          </div>

          <div className="flex items-center gap-2 px-1">
            <input
              id="include-images"
              type="checkbox"
              checked={includeImages}
              onChange={(e) => setIncludeImages(e.checked)}
              className="size-4 rounded border-slate-300 text-slate-900 focus:ring-slate-900"
