            </label>
          </div>

          {actionError ? (
            <p className="text-xs text-red-500">{actionError}</p>
          ) : null}

          <button
            type="button"
            onClick={handleSearchSubmit}
            disabled={isSearching || !searchQuery.trim()}
            className="flex items-center justify-center gap-2 rounded-full bg-slate-900 py-3 text-sm font-medium text-white transition hover:bg-slate-800 disabled:opacity-50"
          >
            {isSearching ? 'Searching...' : 'Search & Scrape'}
          </button>
        </div>
      </WorkspaceActionPanel>
    ) : null}

    {activePanel === 'template' ? (
      <TemplateGalleryModal
        templates={contentTemplates}
        onSelect={handleTemplateSubmit}
        onClose={closePanel}
        isApplying={isApplyingTemplate}
      />
    ) : null}

