'use client';

import { X, Search, Plus, ExternalLink, ImageIcon, Video, Sparkles, AlertCircle } from 'lucide-react';
import { useState, useMemo } from 'react';
import { ContentTemplate } from '../../lib/templates/catalog';

type TemplateGalleryModalProps = {
  templates: ContentTemplate[];
  onSelect: (templateId: string) => void;
  onClose: () => void;
  onSync?: () => void;
  isApplying?: boolean;
};

export function TemplateGalleryModal({
  templates,
  onSelect,
  onClose,
  onSync,
  isApplying = false,
}: TemplateGalleryModalProps) {
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('All');

  const categories = useMemo(() => {
    const cats = ['All', ...new Set(templates.map((t) => t.category))];
    return cats;
  }, [templates]);

  const filteredTemplates = useMemo(() => {
    return templates.filter((t) => {
      const matchesSearch = t.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           t.description.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = activeCategory === 'All' || t.category === activeCategory;
      return matchesSearch && matchesCategory;
    });
  }, [templates, searchQuery, activeCategory]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 p-4 backdrop-blur-sm sm:p-6 md:p-10">
      <div className="flex h-full max-h-[90vh] w-full max-w-6xl flex-col overflow-hidden rounded-[32px] border border-white/20 bg-white/95 shadow-2xl backdrop-blur-xl">
        {/* Header */}
        <div className="flex items-center justify-between border-b border-slate-100 px-6 py-5 sm:px-8">
          <div>
            <h2 className="text-xl font-bold text-slate-900">Template Gallery</h2>
            <p className="text-sm text-slate-500">Pick a reusable content pack for your board.</p>
          </div>
          <button
            onClick={onClose}
            className="flex size-10 items-center justify-center rounded-full border border-slate-200 bg-white text-slate-500 transition hover:bg-slate-50 hover:text-slate-900"
          >
            <X className="size-5" />
          </button>
        </div>

        {/* Toolbar */}
        <div className="flex flex-col gap-4 border-b border-slate-100 bg-slate-50/50 px-6 py-4 sm:flex-row sm:items-center sm:px-8">
          <div className="relative flex-1">
            <Search className="absolute left-3.5 top-1/2 size-4 -translate-y-1/2 text-slate-400" />
            <input
              type="text"
              placeholder="Search templates..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full rounded-full border border-slate-200 bg-white py-2 pl-10 pr-4 text-sm outline-none transition focus:border-slate-400 focus:ring-2 focus:ring-slate-400/10"
            />
          </div>
          <div className="flex flex-wrap gap-2">
            {categories.map((cat) => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={[
                  'rounded-full px-4 py-1.5 text-xs font-semibold transition',
                  activeCategory === cat
                    ? 'bg-slate-900 text-white'
                    : 'bg-white border border-slate-200 text-slate-600 hover:border-slate-300',
                ].join(' ')}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 sm:p-8">
          {filteredTemplates.length > 0 ? (
            <div className="columns-1 gap-6 sm:columns-2 lg:columns-3 xl:columns-3">
              {filteredTemplates.map((template) => (
                <TemplateCard
                  key={template.id}
                  template={template}
                  onSelect={onSelect}
                  isApplying={isApplying}
                />
              ))}
            </div>
          ) : (
            <div className="flex h-full flex-col items-center justify-center py-20 text-center">
              <div className="flex size-16 items-center justify-center rounded-3xl bg-slate-100 text-slate-400">
                <AlertCircle className="size-8" />
              </div>
              <h3 className="mt-4 text-lg font-semibold text-slate-900">No templates found</h3>
              <p className="mt-2 text-slate-500">
                {templates.length === 0 
                  ? "We couldn't find any templates. Try connecting to Supabase."
                  : "Try adjusting your search or category filters."}
              </p>
              {templates.length === 0 && onSync && (
                <button 
                   className="mt-6 rounded-full bg-slate-900 px-6 py-2.5 text-sm font-medium text-white transition hover:bg-slate-800"
                   onClick={onSync}
                >
                  Sync from Supabase
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function TemplateCard({ 
  template, 
  onSelect, 
  isApplying 
}: { 
  template: ContentTemplate; 
  onSelect: (id: string) => void;
  isApplying: boolean;
}) {
  const referenceAsset = template.assets?.find(a => a.type === 'image') || template.assets?.[0];

  return (
    <div className="group mb-6 break-inside-avoid overflow-hidden rounded-[24px] border border-slate-200 bg-white transition hover:border-slate-300 hover:shadow-xl">
      <div className="relative aspect-[4/5] overflow-hidden bg-slate-100">
        {referenceAsset?.type === 'image' ? (
          <img 
            src={referenceAsset.src} 
            alt={template.title}
            className="h-full w-full object-cover transition duration-500 group-hover:scale-105"
          />
        ) : referenceAsset?.type === 'video' ? (
          <video 
            src={referenceAsset.src} 
            className="h-full w-full object-cover transition duration-500 group-hover:scale-105"
            muted
            loop
            onMouseOver={(e) => e.currentTarget.play()}
            onMouseOut={(e) => e.currentTarget.pause()}
          />
        ) : (
          <div className="flex h-full w-full items-center justify-center text-slate-300">
            <ImageIcon className="size-12" />
          </div>
        )}

        <div className="absolute inset-0 bg-gradient-to-t from-slate-900/60 via-transparent to-transparent opacity-0 transition duration-300 group-hover:opacity-100" />

        <div className="absolute bottom-4 left-4 right-4 translate-y-2 opacity-0 transition duration-300 group-hover:translate-y-0 group-hover:opacity-100">
          <button
            onClick={() => onSelect(template.id)}
            disabled={isApplying}
            className="flex w-full items-center justify-center gap-2 rounded-full bg-white py-2.5 text-sm font-bold text-slate-900 shadow-lg hover:bg-slate-50 disabled:opacity-50"
          >
            <Plus className="size-4" />
            {isApplying ? 'Adding...' : 'Add to Board'}
          </button>
        </div>

        <div className="absolute left-4 top-4">
          <span className="rounded-full bg-white/90 px-3 py-1 text-[10px] font-bold uppercase tracking-wider text-slate-900 backdrop-blur-sm">
            {template.category}
          </span>
        </div>
      </div>

      <div className="p-5">
        <h4 className="font-bold text-slate-900">{template.title}</h4>
        <p className="mt-1.5 text-sm leading-relaxed text-slate-500">{template.description}</p>

        <div className="mt-4 flex flex-wrap gap-1.5">
          <div className="flex items-center gap-1 rounded-full bg-slate-50 px-2 py-1 text-[10px] font-medium text-slate-500">
            <ImageIcon className="size-3" />
            Ref Asset
          </div>
          <div className="flex items-center gap-1 rounded-full bg-slate-50 px-2 py-1 text-[10px] font-medium text-slate-500">
            <Sparkles className="size-3" />
            Prompts
          </div>
          <div className="flex items-center gap-1 rounded-full bg-slate-50 px-2 py-1 text-[10px] font-medium text-slate-500">
            <Video className="size-3" />
            Video-ready
          </div>
        </div>
      </div>
    </div>
  );
}

